using System; using System.Net.Http; using System.Text; using System.Threading.Tasks; class Program { static async Task Main(string[] args) { using (var client = new HttpClient()) { var loginData = new { username = "admin", password = "admin", captcha = "", websiteId = 1 }; var json = Newtonsoft.Json.JsonConvert.SerializeObject(loginData); var content = new StringContent(json, Encoding.UTF8, "application/json"); var response = await client.PostAsync("http://localhost:5188/api/auth/login", content); var responseContent = await response.Content.ReadAsStringAsync(); Console.WriteLine($"Status Code: {response.StatusCode}"); Console.WriteLine($"Response: {responseContent}"); } } }